class Board:
    def __init__(self):
        self.pieces = self.initialize_board()

    def initialize_board(self):
        pieces = {}
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 1 and row < 3:
                    pieces[(row, col)] = Piece("White", "Man")
                elif (row + col) % 2 == 1 and row > 4:
                    pieces[(row, col)] = Piece("Black", "Man")
        return pieces

    def move_piece(self, move, player):
        from_pos, to_pos = move.split('-')
        from_pos = (int(from_pos[1]) - 1, ord(from_pos[0]) - ord('a'))
        to_pos = (int(to_pos[1]) - 1, ord(to_pos[0]) - ord('a'))

        if self.pieces.get(from_pos) and self.pieces[from_pos].color == player.color:
            # Add logic for moving piece and capturing
            # This is a simplified version
            if to_pos in self.pieces:
                del self.pieces[to_pos]
            self.pieces[to_pos] = self.pieces[from_pos]
            del self.pieces[from_pos]
            return True
        return False

    def is_game_over(self):
        # Add logic to check game over conditions
        return len([piece for piece in self.pieces.values() if piece.color == "Black"]) == 0 or len([piece for piece in self.pieces.values() if piece.color == "White"]) == 0

class Piece:
    def __init__(self, color, type):
        self.color = color
        self.type = type

if __name__ == "__main__":
    board = Board()
    print(board.pieces)
```

